import React, { useState, useEffect } from "react";
import CardContainer from "../../components/CardContainer";
import Header from "../../components/Header";
import { APIs } from "../../Services/apis";
import { GET } from "../../Services/httpClient";
import { useParams } from "react-router-dom";
import SinglePollContainer from "../../components/SinglePollContainer";
const Poll = () => {
  const [data, setData] = useState([]);
  const [metaData, setmetaData] = useState([]);
  const { slug } = useParams();
  const user = localStorage.getItem("user");
  const GUEST_USER_ID = localStorage.getItem("GUEST_USER_ID");

  useEffect(() => {
    fetchdata();
  }, []);
  const fetchdata = async () => {
    if (!GUEST_USER_ID) {
      const GUEST_USER_ID =
        Math.random().toString(36).substring(2, 17) + Math.random().toString(36).substring(2, 15);
      localStorage.setItem("GUEST_USER_ID", GUEST_USER_ID);
    }
    let id = user ? JSON.parse(user)._id : GUEST_USER_ID;
    var res = await GET(APIs.POLLBYSLUG + slug + "/" + id);
    if (res.status === 200) {
      if (res.data) {
        setData(res.data);
        setmetaData(res.data[0].metaData);
      }
    }
  };
  console.log(metaData.meta_keywords);
  return (
    <>
      <Header heading={"HOME"} />
      {data.map((val, index) => {
        
        return <CardContainer val={val} key={index} onVote={fetchdata} />;
      })}
    </>
  );
};

export default Poll;
